public class Main {
    public static void main(String[] args) {
        // Creating objects
        Car myCar = new Car("Toyota", 2022);
        Car friendCar = new Car("Honda", 2020);

        myCar.displayInfo();
        friendCar.displayInfo();
    }
}

class Car {
    String brand;
    int year;

    Car(String brand, int year) {
        this.brand = brand;
        this.year = year;
    }

    void displayInfo() {
        System.out.println(brand + " - " + year);
    }
}
